import{_ as e,o as a,c as s,ag as i}from"./chunks/framework.eQLvDOR_.js";const A=JSON.parse('{"title":"ai-assisted-workflow","description":"","frontmatter":{"title":"ai-assisted-workflow","concept":"AI 辅助工作流","concept_id":"ai-assisted-workflow","aliases":[],"sources":["02_Library/ADK_Agent_Skills/[ADK_Agent_Skills] My AI-Assisted workflow.md"],"related_concepts":["[[progressive-disclosure]]","[[ide-evolution]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/ai-assisted-workflow.md","filePath":"wiki/concepts/ai-assisted-workflow.md","lastUpdated":null}'),o={name:"wiki/concepts/ai-assisted-workflow.md"};function l(r,t,n,d,c,h){return a(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="ai-辅助工作流-ai-assisted-workflow" tabindex="-1">AI 辅助工作流 (AI-Assisted Workflow) <a class="header-anchor" href="#ai-辅助工作流-ai-assisted-workflow" aria-label="Permalink to &quot;AI 辅助工作流 (AI-Assisted Workflow)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>一种将软件开发中“思考与需求验证”前置的工作流。核心主张是人工负责意图梳理与边界约束，利用 AI 进行极其严苛的 PRD 发问与任务拆解，而非直接用 AI 生成代码。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>拒绝直接编程</strong>：认为 AI 擅长实现代码，但极不擅长明确意图、补全隐含假设（来源：<a href="/s/webclips/library/ADK_Agent_Skills/ADK_Agent_Skills - My AI-Assisted workflow.html">[ADK_Agent_Skills] My AI-Assisted workflow.md</a>）</li><li><strong>撰写 AI 友好的需求</strong>：强制先在人类脑中输出 Free-form plan，再由 AI Interviewer 步步发问形成明确的垂直切片层。</li><li><strong>任务作为 Prompt 向下传递</strong>：任务描述本身不再是写给人类同事看的 Notes，而是给下游 AI 写代码时的系统级 Prompt，包含意图和输入输出约束。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>当需要用 AI 构建新功能时，不要打开 IDE 马上写代码。先手写一段纯文本说明目标，让另一个专门做设计的 Agent 审阅你的计划，并针对异常流、非功能性需求反复提问。只有形成确定性的 PRD 或 Issue 后，再让子 Agent 按切片（非横向扩展）进行单点实现。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/vertical-slice-issues.html">vertical-slice-issues</a> — 构成此工作流的具体拆解单元</li><li><a href="/s/webclips/wiki/concepts/narrow-scope-ai-review.html">narrow-scope-ai-review</a> — 结合此工作流在实施阶段配套的验证环节</li></ul><h2 id="源文章引用" tabindex="-1">源文章引用 <a class="header-anchor" href="#源文章引用" aria-label="Permalink to &quot;源文章引用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源</th><th>关键段落摘录</th></tr></thead><tbody><tr><td><a href="/s/webclips/library/ADK_Agent_Skills/ADK_Agent_Skills - My AI-Assisted workflow.html">[ADK_Agent_Skills] My AI-Assisted workflow.md</a></td><td>&quot;What is AI actually good at? Implementation. What is it genuinely bad at? Figuring out what you actually want, catching the assumptions you forgot to make explicit... That’s your job. It will always be your job.&quot;</td></tr></tbody></table>',11)])])}const _=e(o,[["render",l]]);export{A as __pageData,_ as default};
